    } finally {
      setIsLoggingIn(false);
    }
  }, []);

  const logout = useCallback(() => {
    setSignerPubkey(null);
    localStorage.removeItem("nostr_signer_pubkey");
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem("nostr_signer_pubkey");
    if (saved) setSignerPubkey(saved);
  }, []);

  useEffect(() => {
    let disposed = false;

    (async () => {
