  1→import { useState, useEffect, useCallback, useRef } from "react";
  2→import { useFetcher } from "react-router";
  3→import { useInView } from "react-intersection-observer";
  4→import { useQueryStates, parseAsString } from "nuqs";
  5→import { count, eq, desc, and, type SQL } from "drizzle-orm";
  6→import type { Route } from "./+types/home";
  7→import { AppLayout } from "~/components/layout";
  8→import { CardGrid, TweetTimeline, DeckView } from "~/components/feed";
  9→import { Favicon } from "~/components/ui";
 10→import { categoryList, getDomainFromUrl, type FetchRadarItemsResponse, type RadarItemWithCategory, type DeckData, type Period, type Kind } from "~/data/types";
 11→import { radarItems, sources } from "../../db/schema";
 12→
 13→export function meta({}: Route.MetaArgs) {
 14→  return [
 15→    { title: "Radar" },
 16→    { name: "description", content: "Tech radar aggregator" },
 17→  ];
 18→}
 19→
 20→const ITEMS_PER_PAGE = 20;
 21→const DECK_ITEMS_PER_COLUMN = 10;
 22→
 23→const itemSelectFields = {
 24→  id: radarItems.id,
 25→  title: radarItems.title,
 26→  source: radarItems.source,
 27→  sourceName: radarItems.sourceName,
 28→  summary: radarItems.summary,
 29→  image: radarItems.image,
 30→  url: radarItems.url,
 31→  type: radarItems.type,
 32→  metadata: radarItems.metadata,
 33→  timestamp: radarItems.timestamp,
 34→  createdAt: radarItems.createdAt,
 35→  updatedAt: radarItems.updatedAt,
 36→  category: sources.category,
 37→  categorySlug: sources.categorySlug,
 38→  kind: sources.kind,
 39→};
 40→
 41→export async function loader({ request, context }: Route.LoaderArgs) {
 42→  const url = new URL(request.url);
 43→  const categoryParam = url.searchParams.get("category");
 44→  const kindParam = url.searchParams.get("kind");
 45→  const sourceParam = url.searchParams.get("source");
 46→
 47→  const isDeckMode =
 48→    (!categoryParam || categoryParam === "all") &&
 49→    (!sourceParam || sourceParam === "all") &&
 50→    (!kindParam || kindParam === "all");
 51→
 52→  const [sourcesData, sourceCountRows] = await Promise.all([
 53→    context.db.query.sources.findMany({
 54→      orderBy: (sources, { asc }) => [asc(sources.name)],
 55→    }),
 56→    context.db
 57→      .select({ source: radarItems.source, count: count() })
 58→      .from(radarItems)
 59→      .groupBy(radarItems.source),
 60→  ]);
 61→
 62→  const sourceArticleCounts = Object.fromEntries(
 63→    sourceCountRows.map((row) => [row.source, row.count]),
 64→  );
 65→
 66→  if (isDeckMode) {
 67→    const activeCats = categoryList.filter((c) => c.slug !== "all");
 68→
 69→    const categoryResults = await Promise.all(
 70→      activeCats.map((cat) => {
 71→        const conditions = [
 72→          eq(sources.categorySlug, cat.slug),
 73→        ];
 74→        return context.db
 75→          .select(itemSelectFields)
 76→          .from(radarItems)
 77→          .innerJoin(sources, eq(radarItems.source, sources.id))
 78→          .where(and(...conditions))
 79→          .orderBy(desc(radarItems.timestamp))
 80→          .limit(DECK_ITEMS_PER_COLUMN + 1);
 81→      }),
 82→    );
 83→
 84→    const deckData: DeckData = {};
 85→    activeCats.forEach((cat, i) => {
 86→      const rows = categoryResults[i];
 87→      const hasMore = rows.length > DECK_ITEMS_PER_COLUMN;
 88→      deckData[cat.slug] = {
 89→        items: hasMore ? rows.slice(0, DECK_ITEMS_PER_COLUMN) : rows,
 90→        hasMore,
 91→      };
 92→    });
 93→
 94→    return {
 95→      deckData,
 96→      sources: sourcesData,
 97→      sourceArticleCounts,
 98→      radarItems: [] as RadarItemWithCategory[],
 99→      hasMore: false,
100→      currentPage: 1,
101→    };
102→  }
103→
104→  // Non-deck mode: existing behavior
105→  const conditions: SQL[] = [];
106→  if (kindParam && kindParam !== "all") {
107→    conditions.push(eq(sources.kind, kindParam));
108→  }
109→  if (categoryParam && categoryParam !== "all") {
110→    conditions.push(eq(sources.categorySlug, categoryParam));
111→  }
112→  if (sourceParam && sourceParam !== "all") {
113→    conditions.push(eq(radarItems.source, sourceParam));
114→  }
115→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
116→
117→  const [totalCountResult, items] = await Promise.all([
118→    context.db
119→      .select({ count: count() })
120→      .from(radarItems)
121→      .innerJoin(sources, eq(radarItems.source, sources.id))
122→      .where(whereClause),
123→    context.db
124→      .select(itemSelectFields)
125→      .from(radarItems)
126→      .innerJoin(sources, eq(radarItems.source, sources.id))
127→      .where(whereClause)
128→      .orderBy(desc(radarItems.timestamp))
129→      .limit(ITEMS_PER_PAGE),
130→  ]);
131→
132→  const totalCount = totalCountResult[0]?.count ?? 0;
133→  const hasMore = items.length < totalCount;
134→
135→  return {
136→    deckData: null as DeckData | null,
137→    radarItems: items,
138→    sources: sourcesData,
139→    sourceArticleCounts,
140→    hasMore,
141→    currentPage: 1,
142→  };
143→}
144→
145→function CategoryFilter({
146→  selectedCategorySlug,
147→  onSelect,
148→}: {
149→  selectedCategorySlug: string;
150→  onSelect: (slug: string) => void;
151→}) {
152→  return (
153→    <div className="flex gap-1.5 overflow-x-auto pb-1 mt-3">
154→      {categoryList.map((cat) => (
155→        <button
156→          key={cat.slug}
157→          onClick={() => onSelect(cat.slug)}
158→          className={`px-2.5 py-1 text-xs rounded-full whitespace-nowrap transition-colors ${
159→            selectedCategorySlug === cat.slug
160→              ? "bg-gray-800 text-white"
161→              : "bg-gray-100 text-gray-500 hover:bg-gray-200 hover:text-gray-600"
162→          }`}
163→        >
164→          {cat.name}
165→        </button>
166→      ))}
167→    </div>
168→  );
169→}
170→
171→function normalizePeriod(value: string): Period {
172→  return value === "Today" || value === "Month" || value === "All" ? value : "All";
173→}
174→
175→function normalizeKind(value: string): Kind {
176→  return ["all", "articles", "releases", "video", "podcast", "twitter"].includes(value)
177→    ? (value as Kind)
178→    : "all";
179→}
180→
181→export default function Home({ loaderData }: Route.ComponentProps) {
182→  const fetcher = useFetcher<FetchRadarItemsResponse>();
183→
184→  const [query, setQuery] = useQueryStates(
185→    {
186→      category: parseAsString.withDefault("all"),
187→      source: parseAsString.withDefault("all"),
188→      period: parseAsString.withDefault("All"),
189→      kind: parseAsString.withDefault("all"),
190→    },
191→    { history: "replace" },
192→  );
193→
194→  const categorySlug = query.category;
195→  const selectedSource = query.source;
196→  const selectedPeriod = normalizePeriod(query.period);
197→  const selectedKind = normalizeKind(query.kind);
198→
199→  const isDeckMode = categorySlug === "all" && selectedSource === "all" && selectedKind === "all";
200→
201→  const setSelectedKind = useCallback((kind: Kind) => {
202→    void setQuery({ kind });
203→  }, [setQuery]);
204→
205→  const setSelectedPeriod = useCallback((period: Period) => {
206→    void setQuery({ period });
207→  }, [setQuery]);
208→
209→  const handleSourceChange = useCallback((source: string) => {
210→    if (source !== "all") {
211→      void setQuery({ source, kind: "all", category: "all" });
212→      return;
213→    }
214→    void setQuery({ source });
215→  }, [setQuery]);
216→
217→  const handleCategoryChange = useCallback((category: string) => {
218→    void setQuery({ category, source: "all" });
219→  }, [setQuery]);
220→
221→  // --- Non-deck mode state ---
222→  const [items, setItems] = useState<FetchRadarItemsResponse["radarItems"]>(
223→    loaderData.radarItems as FetchRadarItemsResponse["radarItems"],
224→  );
225→  const [page, setPage] = useState(loaderData.currentPage);
226→  const [hasMore, setHasMore] = useState(loaderData.hasMore);
227→  const [isLoading, setIsLoading] = useState(false);
228→  const isResetRef = useRef(false);
229→
230→  const isFirstRender = useRef(true);
231→  useEffect(() => {
232→    if (isFirstRender.current) {
233→      isFirstRender.current = false;
234→      return;
235→    }
236→
237→    if (isDeckMode) return;
238→
239→    setItems([]);
240→    setPage(1);
241→    setHasMore(true);
242→    setIsLoading(true);
243→    isResetRef.current = true;
244→
245→    const params = new URLSearchParams({ page: "1" });
246→    if (selectedKind !== "all") params.set("kind", selectedKind);
247→    if (categorySlug !== "all") params.set("category", categorySlug);
248→    if (selectedSource !== "all") params.set("source", selectedSource);
249→
250→    fetcher.load(`/api/radar-items?${params.toString()}`);
251→    // eslint-disable-next-line react-hooks/exhaustive-deps
252→  }, [selectedKind, selectedSource, categorySlug]);
253→
254→  // 無限スクロール: 次ページ読み込み
255→  const loadMore = useCallback(() => {
256→    if (hasMore && fetcher.state === "idle" && !isLoading) {
257→      const nextPage = page + 1;
258→      setPage(nextPage);
259→      setIsLoading(true);
260→      isResetRef.current = false;
261→      const params = new URLSearchParams({ page: String(nextPage) });
262→      if (selectedKind !== "all") params.set("kind", selectedKind);
263→      if (categorySlug !== "all") params.set("category", categorySlug);
264→      if (selectedSource !== "all") params.set("source", selectedSource);
265→      fetcher.load(`/api/radar-items?${params.toString()}`);
266→    }
267→  }, [hasMore, page, fetcher, isLoading, selectedKind, categorySlug, selectedSource]);
268→
269→  // fetcher レスポンス処理
270→  useEffect(() => {
271→    const data = fetcher.data;
272→    if (data?.radarItems) {
273→      if (isResetRef.current) {
274→        setItems(data.radarItems);
275→        isResetRef.current = false;
276→      } else {
277→        setItems((prev) => [...prev, ...data.radarItems]);
278→      }
279→      setHasMore(data.hasMore);
280→      setIsLoading(false);
281→    }
282→  }, [fetcher.data]);
283→
284→  const { ref: observerRef, inView } = useInView({
285→    threshold: 0,
286→    rootMargin: "100px",
287→  });
288→
289→  useEffect(() => {
290→    if (inView && hasMore && fetcher.state === "idle" && !isLoading) {
291→      loadMore();
292→    }
293→  }, [inView, hasMore, fetcher.state, loadMore, isLoading]);
294→
295→  // period のみクライアントサイドフィルタ
296→  const filteredItems = items.filter((f) => {
297→    if (selectedPeriod === "All") return true;
298→    const now = new Date();
299→    const itemDate = new Date(f.timestamp);
300→    if (selectedPeriod === "Today") {
301→      return itemDate.toDateString() === now.toDateString();
302→    }
303→    if (selectedPeriod === "Month") {
304→      const oneMonthAgo = new Date();
305→      oneMonthAgo.setMonth(oneMonthAgo.getMonth() - 1);
306→      return itemDate >= oneMonthAgo;
307→    }
308→    return true;
309→  });
310→
311→  const selectedSourceData = selectedSource !== "all"
312→    ? loaderData.sources.find((s) => s.id === selectedSource)
313→    : undefined;
314→  const selectedSourceCount = selectedSourceData
315→    ? loaderData.sourceArticleCounts[selectedSourceData.id] ?? 0
316→    : 0;
317→
318→  return (
319→    <AppLayout
320→      title="Radar"
321→      selectedSource={selectedSource}
322→      setSelectedSource={handleSourceChange}
323→      selectedPeriod={selectedPeriod}
324→      setSelectedPeriod={setSelectedPeriod}
325→      selectedKind={selectedKind}
326→      setSelectedKind={setSelectedKind}
327→      showSourceFilter={true}
328→      sources={loaderData.sources}
329→      isDeckMode={isDeckMode}
330→      headerContent={
331→        isDeckMode ? undefined : (
332→          selectedSourceData ? (
333→            <div className="flex items-center gap-2.5">
334→              <Favicon domain={getDomainFromUrl(selectedSourceData.url)} size={20} />
335→              <span className="text-sm font-medium text-gray-900">{selectedSourceData.name}</span>
336→              <span className="text-xs text-gray-400">{selectedSourceCount} articles</span>
337→            </div>
338→          ) : (
339→            <CategoryFilter selectedCategorySlug={categorySlug} onSelect={handleCategoryChange} />
340→          )
341→        )
342→      }
343→    >
344→      {isDeckMode && loaderData.deckData ? (
345→        <DeckView
346→          deckData={loaderData.deckData}
347→          selectedKind={selectedKind}
348→          selectedPeriod={selectedPeriod}
349→        />
350→      ) : (
351→        <>
352→          {selectedKind === "twitter" ? (
353→            <div className="-m-4">
354→              <TweetTimeline items={filteredItems} />
355→            </div>
356→          ) : (
357→            <CardGrid items={filteredItems} />
358→          )}
359→          {filteredItems.length === 0 && (
360→            <div className="text-center py-12 text-gray-500">
361→              該当する記事がありません
362→            </div>
363→          )}
364→
365→          {hasMore && filteredItems.length > 0 && (
366→            <div ref={observerRef} className="p-2.5 text-center">
367→              {isLoading && (
368→                <div className="flex justify-center items-center">
369→                  <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-gray-900"></div>
370→                </div>
371→              )}
372→            </div>
373→          )}
374→        </>
375→      )}
376→    </AppLayout>
377→  );
378→}
