  1→import { useEffect, useRef, useState, useCallback, useMemo } from "react";
  2→import { NOSTR_RELAYS, OWNER_NPUB } from "~/data/nostr-config";
  3→
  4→export interface NostrNote {
  5→  id: string;
  6→  pubkey: string;
  7→  content: string;
  8→  created_at: number;
  9→  tags: string[][];
 10→}
 11→
 12→export interface NostrProfile {
 13→  name?: string;
 14→  display_name?: string;
 15→  picture?: string;
 16→  about?: string;
 17→}
 18→
 19→declare global {
 20→  interface Window {
 21→    nostr?: {
 22→      getPublicKey(): Promise<string>;
 23→      signEvent(event: unknown): Promise<unknown>;
 24→    };
 25→  }
 26→}
 27→
 28→const MAX_NOTES = 200;
 29→
 30→function addNote(
 31→  prev: NostrNote[],
 32→  ev: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] },
 33→) {
 34→  if (prev.some((n) => n.id === ev.id)) return prev;
 35→  const next = [
 36→    { id: ev.id, pubkey: ev.pubkey, content: ev.content, created_at: ev.created_at, tags: ev.tags },
 37→    ...prev,
 38→  ];
 39→  next.sort((a, b) => b.created_at - a.created_at);
 40→  return next.slice(0, MAX_NOTES);
 41→}
 42→
 43→export function useNostr() {
 44→  const [signerPubkey, setSignerPubkey] = useState<string | null>(null);
 45→  const [ownerHex, setOwnerHex] = useState<string | null>(null);
 46→  const [follows, setFollows] = useState<string[]>([]);
 47→  const [notes, setNotes] = useState<NostrNote[]>([]);
 48→  const [globalNotes, setGlobalNotes] = useState<NostrNote[]>([]);
 49→  const [profiles, setProfiles] = useState<Map<string, NostrProfile>>(
 50→    new Map(),
 51→  );
 52→  const [isConnected, setIsConnected] = useState(false);
 53→  const [isLoggingIn, setIsLoggingIn] = useState(false);
 54→  const disposeFnRef = useRef<(() => void) | null>(null);
 55→
 56→  const login = useCallback(async () => {
 57→    if (!window.nostr) {
 58→      throw new Error("NIP-07 extension not found");
 59→    }
 60→    setIsLoggingIn(true);
 61→    try {
 62→      const pk = await window.nostr.getPublicKey();
 63→      setSignerPubkey(pk);
 64→      localStorage.setItem("nostr_signer_pubkey", pk);
 65→    } finally {
 66→      setIsLoggingIn(false);
 67→    }
 68→  }, []);
 69→
 70→  const logout = useCallback(() => {
 71→    setSignerPubkey(null);
 72→    localStorage.removeItem("nostr_signer_pubkey");
 73→  }, []);
 74→
 75→  useEffect(() => {
 76→    const saved = localStorage.getItem("nostr_signer_pubkey");
 77→    if (saved) setSignerPubkey(saved);
 78→  }, []);
 79→
 80→  useEffect(() => {
 81→    let disposed = false;
 82→
 83→    (async () => {
 84→      const {
 85→        createRxNostr,
 86→        createRxForwardReq,
 87→        createRxBackwardReq,
 88→      } = await import("rx-nostr");
 89→      const { verifier } = await import("rx-nostr-crypto");
 90→      const { nip19 } = await import("nostr-tools");
 91→
 92→      if (disposed) return;
 93→
 94→      const hex = nip19.decode(OWNER_NPUB).data as string;
 95→      setOwnerHex(hex);
 96→
 97→      const rxNostr = createRxNostr({ verifier });
 98→      rxNostr.setDefaultRelays(NOSTR_RELAYS);
 99→      disposeFnRef.current = () => rxNostr.dispose();
100→
101→      // Profile handler (shared)
102→      const handleProfile = (packet: { event: { pubkey: string; content: string } }) => {
103→        try {
104→          const profile = JSON.parse(packet.event.content) as NostrProfile;
105→          setProfiles((prev) => {
106→            const next = new Map(prev);
107→            next.set(packet.event.pubkey, profile);
108→            return next;
109→          });
110→        } catch {
111→          /* ignore */
112→        }
113→      };
114→
115→      // Fetch contact list (kind:3)
116→      const followPubkeys: string[] = [];
117→
118→      await new Promise<void>((resolve) => {
119→        const timeout = setTimeout(() => resolve(), 10_000);
120→        const contactReq = createRxBackwardReq();
121→        rxNostr.use(contactReq).subscribe({
122→          next: (packet) => {
123→            for (const tag of packet.event.tags) {
124→              if (tag[0] === "p" && tag[1]) {
125→                followPubkeys.push(tag[1]);
126→              }
127→            }
128→          },
129→          complete: () => {
130→            clearTimeout(timeout);
131→            resolve();
132→          },
133→        });
134→        contactReq.emit([{ kinds: [3], authors: [hex], limit: 1 }]);
135→        contactReq.over();
136→      });
137→
138→      if (disposed) return;
139→
140→      const authors = [hex, ...followPubkeys];
141→      setFollows(followPubkeys);
142→      setIsConnected(true);
143→
144→      if (authors.length === 0) return;
145→
146→      const handleNote = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
147→        setNotes((prev) => addNote(prev, packet.event));
148→      };
149→
150→      // Past notes (followed)
151→      const pastReq = createRxBackwardReq();
152→      rxNostr.use(pastReq).subscribe(handleNote);
153→      pastReq.emit([{ kinds: [1], authors, limit: 50 }]);
154→      pastReq.over();
155→
