    setHasExtension(!!window.nostr);
  }, []);

  return {
    signerPubkey,
    ownerHex,
    follows,
    notes,
    globalNotes,
    myNotes,
    timelineNotes,
    taggedNotes,
    noteStats,
    profiles,
    isConnected,
    isLoggingIn,
    hasExtension,
    login,
    logout,
  };
}

