 93→        createRxNostr,
 94→        createRxForwardReq,
 95→        createRxBackwardReq,
 96→        batch,
 97→        uniq,
 98→      } = await import("rx-nostr");
 99→      const { verifier } = await import("rx-nostr-crypto");
100→      const { nip19 } = await import("nostr-tools");
101→      const { bufferWhen, interval } = await import("rxjs");
102→
103→      if (disposed) return;
104→
105→      const hex = nip19.decode(OWNER_NPUB).data as string;
106→      setOwnerHex(hex);
107→
108→      const rxNostr = createRxNostr({ verifier });
109→      rxNostr.setDefaultRelays(NOSTR_RELAYS);
110→      rxNostrRef.current = rxNostr;
111→      disposeFnRef.current = () => {
112→        rxNostr.dispose();
113→        rxNostrRef.current = null;
114→      };
115→
116→      // Shared profile handler
117→      const handleProfile = (packet: { event: { pubkey: string; content: string } }) => {
