121→            if (prev.get(packet.event.pubkey)) return prev;
122→            const next = new Map(prev);
123→            next.set(packet.event.pubkey, profile);
124→            return next;
125→          });
126→        } catch {
127→          /* ignore malformed */
128→        }
129→      };
130→
131→      // Batched profile fetcher for unknown pubkeys
132→      const fetchedProfilePubkeys = new Set<string>();
133→      const profileBatchReq = createRxForwardReq();
134→      rxNostr
135→        .use(
136→          profileBatchReq.pipe(
137→            bufferWhen(() => interval(1000)),
138→            batch(),
139→          ),
140→        )
141→        .pipe(uniq())
142→        .subscribe({ next: handleProfile });
143→
144→      const ensureProfile = (pubkey: string) => {
145→        if (fetchedProfilePubkeys.has(pubkey)) return;
146→        fetchedProfilePubkeys.add(pubkey);
147→        profileBatchReq.emit([{ kinds: [0], authors: [pubkey], limit: 1 }]);
148→      };
149→
150→      // Fetch contact list (kind:3)
151→      const followPubkeys: string[] = [];
152→
153→      await new Promise<void>((resolve) => {
154→        const timeout = setTimeout(() => resolve(), 10_000);
155→        const contactReq = createRxBackwardReq();
156→        rxNostr.use(contactReq).pipe(uniq()).subscribe({
157→          next: (packet) => {
158→            for (const tag of packet.event.tags) {
159→              if (tag[0] === "p" && tag[1]) {
160→                followPubkeys.push(tag[1]);
161→              }
162→            }
163→          },
164→          complete: () => {
165→            clearTimeout(timeout);
166→            resolve();
167→          },
168→        });
169→        contactReq.emit([{ kinds: [3], authors: [hex], limit: 1 }]);
170→        contactReq.over();
171→      });
