173→      if (disposed) return;
174→
175→      const authors = [hex, ...followPubkeys];
176→      setFollows(followPubkeys);
177→      setIsConnected(true);
178→
179→      // Pre-register all followed authors for profile fetching
180→      for (const a of authors) fetchedProfilePubkeys.add(a);
181→
182→      if (authors.length === 0) return;
183→
184→      // Note handler: add note + ensure profile is fetched
185→      const handleNote = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
186→        setNotes((prev) => addNote(prev, packet.event));
187→        ensureProfile(packet.event.pubkey);
188→      };
189→
190→      // Past notes (followed) with dedup
191→      const pastReq = createRxBackwardReq();
192→      rxNostr.use(pastReq).pipe(uniq()).subscribe(handleNote);
193→      pastReq.emit([{ kinds: [1], authors, limit: 50 }]);
194→      pastReq.over();
195→
196→      // Real-time notes (followed) with dedup
197→      const liveReq = createRxForwardReq();
198→      rxNostr.use(liveReq).pipe(uniq()).subscribe(handleNote);
199→      liveReq.emit([{ kinds: [1], authors }]);
200→
201→      // Profiles for followed authors (bulk fetch with dedup)
202→      const profileReq = createRxBackwardReq();
203→      rxNostr.use(profileReq).pipe(uniq()).subscribe(handleProfile);
204→      profileReq.emit([{ kinds: [0], authors }]);
205→      profileReq.over();
206→
207→      // Reactions & reposts (kind:7 and kind:6) for followed authors' notes
208→      const handleReaction = (packet: { event: { tags: string[][]; kind: number } }) => {
209→        const eTag = packet.event.tags.find((t) => t[0] === "e");
210→        if (!eTag?.[1]) return;
211→        const noteId = eTag[1];
