213→          const existing = prev.get(noteId) ?? { reactions: 0, reposts: 0 };
214→          const next = new Map(prev);
215→          if (packet.event.kind === 7) {
216→            next.set(noteId, { ...existing, reactions: existing.reactions + 1 });
217→          } else if (packet.event.kind === 6) {
218→            next.set(noteId, { ...existing, reposts: existing.reposts + 1 });
