225→      rxNostr.use(reactionReq).pipe(uniq()).subscribe(handleReaction);
226→      reactionReq.emit([{ kinds: [7, 6], "#p": authors, limit: 100 }]);
227→      reactionReq.over();
228→
229→      const liveReactionReq = createRxForwardReq();
230→      rxNostr.use(liveReactionReq).pipe(uniq()).subscribe(handleReaction);
231→      liveReactionReq.emit([{ kinds: [7, 6], "#p": authors }]);
232→
233→      // Global feed with dedup
234→      const handleGlobalNote = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
235→        setGlobalNotes((prev) => addNote(prev, packet.event));
236→        ensureProfile(packet.event.pubkey);
237→      };
238→
239→      const globalPastReq = createRxBackwardReq();
240→      rxNostr.use(globalPastReq).pipe(uniq()).subscribe(handleGlobalNote);
241→      globalPastReq.emit([{ kinds: [1], limit: 50 }]);
242→      globalPastReq.over();
243→
244→      const globalLiveReq = createRxForwardReq();
245→      rxNostr.use(globalLiveReq).pipe(uniq()).subscribe(handleGlobalNote);
