260→    [notes, ownerHex],
261→  );
262→
263→  const timelineNotes = useMemo(
264→    () => (ownerHex ? notes.filter((n) => n.pubkey !== ownerHex) : notes),
265→    [notes, ownerHex],
266→  );
267→
268→  const taggedNotes = useMemo(
269→    () => notes.filter((n) => n.tags.some((t) => t[0] === "t")),
270→    [notes],
271→  );
272→
273→  const isOwner = !!(signerPubkey && ownerHex && signerPubkey === ownerHex);
274→
275→  const publish = useCallback(async (content: string) => {
276→    if (!window.nostr || !rxNostrRef.current || !isOwner) {
277→      throw new Error("Cannot publish: not logged in as owner");
278→    }
279→    setIsPublishing(true);
280→    try {
281→      const unsignedEvent = {
282→        kind: 1,
283→        content,
284→        tags: [] as string[][],
285→        created_at: Math.floor(Date.now() / 1000),
286→      };
287→      const signedEvent = await window.nostr.signEvent(unsignedEvent);
288→      rxNostrRef.current.send(signedEvent);
289→      // Optimistically add to local notes
290→      const ev = signedEvent as { id: string; pubkey: string; content: string; created_at: number; tags: string[][] };
291→      setNotes((prev) => addNote(prev, ev));
292→    } finally {
293→      setIsPublishing(false);
294→    }
295→  }, [isOwner]);
296→
297→  const [hasExtension, setHasExtension] = useState(false);
298→  useEffect(() => {
299→    setHasExtension(!!window.nostr);
300→  }, []);
301→
302→  return {
303→    signerPubkey,
304→    ownerHex,
305→    follows,
306→    notes,
307→    globalNotes,
308→    myNotes,
309→    timelineNotes,
310→    taggedNotes,
311→    noteStats,
312→    profiles,
313→    isConnected,
314→    isLoggingIn,
315→    isOwner,
316→    isPublishing,
317→    hasExtension,
318→    login,
319→    logout,
320→    publish,
321→  };
322→}
