 20→const ITEMS_PER_PAGE = 20;
 21→const DECK_ITEMS_PER_COLUMN = 10;
 22→
 23→const itemSelectFields = {
 24→  id: radarItems.id,
 25→  title: radarItems.title,
 26→  source: radarItems.source,
 27→  sourceName: radarItems.sourceName,
 28→  summary: radarItems.summary,
 29→  image: radarItems.image,
 30→  url: radarItems.url,
 31→  type: radarItems.type,
 32→  metadata: radarItems.metadata,
 33→  timestamp: radarItems.timestamp,
 34→  createdAt: radarItems.createdAt,
 35→  updatedAt: radarItems.updatedAt,
 36→  category: sources.category,
 37→  categorySlug: sources.categorySlug,
 38→  kind: sources.kind,
 39→};
 40→
 41→export async function loader({ request, context }: Route.LoaderArgs) {
 42→  const url = new URL(request.url);
 43→  const categoryParam = url.searchParams.get("category");
 44→  const kindParam = url.searchParams.get("kind");
 45→  const sourceParam = url.searchParams.get("source");
 46→
 47→  const isDeckMode =
 48→    (!categoryParam || categoryParam === "all") &&
 49→    (!sourceParam || sourceParam === "all") &&
 50→    (!kindParam || kindParam === "all");
 51→
 52→  const [sourcesData, sourceCountRows] = await Promise.all([
 53→    context.db.query.sources.findMany({
 54→      orderBy: (sources, { asc }) => [asc(sources.name)],
 55→    }),
 56→    context.db
 57→      .select({ source: radarItems.source, count: count() })
 58→      .from(radarItems)
 59→      .groupBy(radarItems.source),
 60→  ]);
 61→
 62→  const sourceArticleCounts = Object.fromEntries(
 63→    sourceCountRows.map((row) => [row.source, row.count]),
 64→  );
 65→
 66→  if (isDeckMode) {
 67→    const activeCats = categoryList.filter((c) => c.slug !== "all");
 68→
 69→    const categoryResults = await Promise.all(
 70→      activeCats.map((cat) => {
 71→        const conditions = [
 72→          eq(sources.categorySlug, cat.slug),
 73→        ];
 74→        return context.db
 75→          .select(itemSelectFields)
 76→          .from(radarItems)
 77→          .innerJoin(sources, eq(radarItems.source, sources.id))
 78→          .where(and(...conditions))
 79→          .orderBy(desc(radarItems.timestamp))
 80→          .limit(DECK_ITEMS_PER_COLUMN + 1);
 81→      }),
 82→    );
 83→
 84→    const deckData: DeckData = {};
 85→    activeCats.forEach((cat, i) => {
 86→      const rows = categoryResults[i];
 87→      const hasMore = rows.length > DECK_ITEMS_PER_COLUMN;
 88→      deckData[cat.slug] = {
 89→        items: hasMore ? rows.slice(0, DECK_ITEMS_PER_COLUMN) : rows,
 90→        hasMore,
 91→      };
 92→    });
 93→
 94→    return {
 95→      deckData,
 96→      sources: sourcesData,
 97→      sourceArticleCounts,
 98→      radarItems: [] as RadarItemWithCategory[],
 99→      hasMore: false,
100→      currentPage: 1,
101→    };
102→  }
103→
104→  // Non-deck mode: existing behavior
105→  const conditions: SQL[] = [];
106→  if (kindParam && kindParam !== "all") {
107→    conditions.push(eq(sources.kind, kindParam));
108→  }
109→  if (categoryParam && categoryParam !== "all") {
110→    conditions.push(eq(sources.categorySlug, categoryParam));
111→  }
112→  if (sourceParam && sourceParam !== "all") {
113→    conditions.push(eq(radarItems.source, sourceParam));
114→  }
115→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
116→
117→  const [totalCountResult, items] = await Promise.all([
118→    context.db
119→      .select({ count: count() })
120→      .from(radarItems)
121→      .innerJoin(sources, eq(radarItems.source, sources.id))
122→      .where(whereClause),
123→    context.db
124→      .select(itemSelectFields)
125→      .from(radarItems)
126→      .innerJoin(sources, eq(radarItems.source, sources.id))
127→      .where(whereClause)
128→      .orderBy(desc(radarItems.timestamp))
129→      .limit(ITEMS_PER_PAGE),
130→  ]);
131→
132→  const totalCount = totalCountResult[0]?.count ?? 0;
133→  const hasMore = items.length < totalCount;
134→
135→  return {
136→    deckData: null as DeckData | null,
137→    radarItems: items,
138→    sources: sourcesData,
139→    sourceArticleCounts,
140→    hasMore,
141→    currentPage: 1,
142→  };
143→}
