  1→import { useEffect, useRef, useState, useCallback, useMemo } from "react";
  2→import { NOSTR_RELAYS, OWNER_NPUB } from "~/data/nostr-config";
  3→
  4→export interface NostrNote {
  5→  id: string;
  6→  pubkey: string;
  7→  content: string;
  8→  created_at: number;
  9→  tags: string[][];
 10→}
 11→
 12→export interface NostrProfile {
 13→  name?: string;
 14→  display_name?: string;
 15→  picture?: string;
 16→  about?: string;
 17→}
 18→
 19→export interface NoteStats {
 20→  reactions: number;
 21→  reposts: number;
 22→}
 23→
 24→export interface NostrNotification {
 25→  id: string;
 26→  kind: number;
 27→  pubkey: string;
 28→  content: string;
 29→  created_at: number;
 30→  tags: string[][];
 31→  targetNoteId?: string;
 32→}
 33→
 34→export interface NostrReaction {
 35→  id: string;
 36→  pubkey: string;
 37→  content: string;
 38→  created_at: number;
 39→  targetNoteId: string;
 40→}
 41→
 42→declare global {
 43→  interface Window {
 44→    nostr?: {
 45→      getPublicKey(): Promise<string>;
 46→      signEvent(event: unknown): Promise<unknown>;
 47→    };
 48→  }
 49→}
 50→
 51→const MAX_NOTES = 200;
 52→
 53→function addNote(
 54→  prev: NostrNote[],
 55→  ev: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] },
 56→) {
 57→  if (prev.some((n) => n.id === ev.id)) return prev;
 58→  const next = [
 59→    { id: ev.id, pubkey: ev.pubkey, content: ev.content, created_at: ev.created_at, tags: ev.tags },
 60→    ...prev,
 61→  ];
 62→  next.sort((a, b) => b.created_at - a.created_at);
 63→  return next.slice(0, MAX_NOTES);
 64→}
 65→
 66→export function useNostr() {
 67→  const [signerPubkey, setSignerPubkey] = useState<string | null>(null);
 68→  const [ownerHex, setOwnerHex] = useState<string | null>(null);
 69→  const [follows, setFollows] = useState<string[]>([]);
 70→  const [notes, setNotes] = useState<NostrNote[]>([]);
 71→  const [globalNotes, setGlobalNotes] = useState<NostrNote[]>([]);
 72→  const [notifications, setNotifications] = useState<NostrNotification[]>([]);
 73→  const [reactions, setReactions] = useState<NostrReaction[]>([]);
 74→  const [noteStats, setNoteStats] = useState<Map<string, NoteStats>>(new Map());
 75→  const [profiles, setProfiles] = useState<Map<string, NostrProfile>>(
 76→    new Map(),
 77→  );
 78→  const [isConnected, setIsConnected] = useState(false);
 79→  const [isLoggingIn, setIsLoggingIn] = useState(false);
 80→  const [isPublishing, setIsPublishing] = useState(false);
 81→  const disposeFnRef = useRef<(() => void) | null>(null);
 82→  const rxNostrRef = useRef<{ send: (event: unknown) => unknown } | null>(null);
 83→
 84→  const login = useCallback(async () => {
 85→    if (!window.nostr) {
 86→      throw new Error("NIP-07 extension not found");
 87→    }
 88→    setIsLoggingIn(true);
 89→    try {
 90→      const pk = await window.nostr.getPublicKey();
 91→      setSignerPubkey(pk);
 92→      localStorage.setItem("nostr_signer_pubkey", pk);
 93→    } finally {
 94→      setIsLoggingIn(false);
 95→    }
 96→  }, []);
 97→
 98→  const logout = useCallback(() => {
 99→    setSignerPubkey(null);
100→    localStorage.removeItem("nostr_signer_pubkey");
101→  }, []);
102→
103→  useEffect(() => {
104→    const saved = localStorage.getItem("nostr_signer_pubkey");
105→    if (saved) setSignerPubkey(saved);
106→  }, []);
107→
108→  useEffect(() => {
109→    let disposed = false;
110→
111→    (async () => {
112→      const {
113→        createRxNostr,
114→        createRxForwardReq,
115→        createRxBackwardReq,
116→        batch,
117→        uniq,
118→      } = await import("rx-nostr");
119→      const { verifier } = await import("rx-nostr-crypto");
120→      const { nip19 } = await import("nostr-tools");
121→      const { bufferWhen, interval } = await import("rxjs");
122→
123→      if (disposed) return;
124→
125→      const hex = nip19.decode(OWNER_NPUB).data as string;
126→      setOwnerHex(hex);
127→
128→      const rxNostr = createRxNostr({ verifier });
129→      rxNostr.setDefaultRelays(NOSTR_RELAYS);
130→      rxNostrRef.current = rxNostr;
131→      disposeFnRef.current = () => {
132→        rxNostr.dispose();
133→        rxNostrRef.current = null;
134→      };
135→
136→      // Shared profile handler
137→      const handleProfile = (packet: { event: { pubkey: string; content: string } }) => {
138→        try {
139→          const profile = JSON.parse(packet.event.content) as NostrProfile;
140→          setProfiles((prev) => {
141→            if (prev.get(packet.event.pubkey)) return prev;
142→            const next = new Map(prev);
143→            next.set(packet.event.pubkey, profile);
144→            return next;
145→          });
146→        } catch {
147→          /* ignore malformed */
148→        }
149→      };
150→
151→      // Batched profile fetcher for unknown pubkeys
152→      const fetchedProfilePubkeys = new Set<string>();
153→      const profileBatchReq = createRxForwardReq();
154→      rxNostr
155→        .use(
156→          profileBatchReq.pipe(
157→            bufferWhen(() => interval(1000)),
158→            batch(),
159→          ),
160→        )
161→        .pipe(uniq())
162→        .subscribe({ next: handleProfile });
163→
164→      const ensureProfile = (pubkey: string) => {
165→        if (fetchedProfilePubkeys.has(pubkey)) return;
166→        fetchedProfilePubkeys.add(pubkey);
167→        profileBatchReq.emit([{ kinds: [0], authors: [pubkey], limit: 1 }]);
168→      };
169→
170→      // Fetch contact list (kind:3)
171→      const followPubkeys: string[] = [];
172→
173→      await new Promise<void>((resolve) => {
174→        const timeout = setTimeout(() => resolve(), 10_000);
175→        const contactReq = createRxBackwardReq();
176→        rxNostr.use(contactReq).pipe(uniq()).subscribe({
177→          next: (packet) => {
178→            for (const tag of packet.event.tags) {
179→              if (tag[0] === "p" && tag[1]) {
180→                followPubkeys.push(tag[1]);
181→              }
182→            }
183→          },
184→          complete: () => {
185→            clearTimeout(timeout);
186→            resolve();
187→          },
188→        });
189→        contactReq.emit([{ kinds: [3], authors: [hex], limit: 1 }]);
190→        contactReq.over();
191→      });
192→
193→      if (disposed) return;
194→
195→      const authors = [hex, ...followPubkeys];
196→      setFollows(followPubkeys);
197→      setIsConnected(true);
198→
199→      // Pre-register all followed authors for profile fetching
200→      for (const a of authors) fetchedProfilePubkeys.add(a);
201→
202→      if (authors.length === 0) return;
203→
204→      // Note handler: add note + ensure profile is fetched
205→      const handleNote = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
206→        setNotes((prev) => addNote(prev, packet.event));
207→        ensureProfile(packet.event.pubkey);
208→      };
209→
210→      // Past notes (followed) with dedup
211→      const pastReq = createRxBackwardReq();
212→      rxNostr.use(pastReq).pipe(uniq()).subscribe(handleNote);
213→      pastReq.emit([{ kinds: [1], authors, limit: 50 }]);
214→      pastReq.over();
215→
216→      // Real-time notes (followed) with dedup
217→      const liveReq = createRxForwardReq();
218→      rxNostr.use(liveReq).pipe(uniq()).subscribe(handleNote);
219→      liveReq.emit([{ kinds: [1], authors }]);
220→
221→      // Profiles for followed authors (bulk fetch with dedup)
222→      const profileReq = createRxBackwardReq();
223→      rxNostr.use(profileReq).pipe(uniq()).subscribe(handleProfile);
224→      profileReq.emit([{ kinds: [0], authors }]);
225→      profileReq.over();
226→
227→      // Reactions & reposts (kind:7 and kind:6) for followed authors' notes
228→      const handleReaction = (packet: { event: { tags: string[][]; kind: number } }) => {
229→        const eTag = packet.event.tags.find((t) => t[0] === "e");
230→        if (!eTag?.[1]) return;
231→        const noteId = eTag[1];
232→        setNoteStats((prev) => {
233→          const existing = prev.get(noteId) ?? { reactions: 0, reposts: 0 };
234→          const next = new Map(prev);
235→          if (packet.event.kind === 7) {
236→            next.set(noteId, { ...existing, reactions: existing.reactions + 1 });
237→          } else if (packet.event.kind === 6) {
238→            next.set(noteId, { ...existing, reposts: existing.reposts + 1 });
239→          }
240→          return next;
241→        });
242→      };
243→
244→      const reactionReq = createRxBackwardReq();
245→      rxNostr.use(reactionReq).pipe(uniq()).subscribe(handleReaction);
246→      reactionReq.emit([{ kinds: [7, 6], "#p": authors, limit: 100 }]);
247→      reactionReq.over();
248→
249→      const liveReactionReq = createRxForwardReq();
250→      rxNostr.use(liveReactionReq).pipe(uniq()).subscribe(handleReaction);
251→      liveReactionReq.emit([{ kinds: [7, 6], "#p": authors }]);
252→
253→      // Global feed with dedup
254→      const handleGlobalNote = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
255→        setGlobalNotes((prev) => addNote(prev, packet.event));
256→        ensureProfile(packet.event.pubkey);
257→      };
258→
259→      const globalPastReq = createRxBackwardReq();
260→      rxNostr.use(globalPastReq).pipe(uniq()).subscribe(handleGlobalNote);
261→      globalPastReq.emit([{ kinds: [1], limit: 50 }]);
262→      globalPastReq.over();
263→
264→      const globalLiveReq = createRxForwardReq();
265→      rxNostr.use(globalLiveReq).pipe(uniq()).subscribe(handleGlobalNote);
266→      globalLiveReq.emit([{ kinds: [1] }]);
267→
268→      // Notifications: mentions (kind:1 with p-tag) + reactions/reposts to owner's notes
269→      const addNotification = (ev: { id: string; kind: number; pubkey: string; content: string; created_at: number; tags: string[][] }) => {
270→        const targetNoteId = ev.tags.find((t) => t[0] === "e")?.[1];
271→        setNotifications((prev) => {
272→          if (prev.some((n) => n.id === ev.id)) return prev;
273→          const next = [{ ...ev, targetNoteId }, ...prev];
274→          next.sort((a, b) => b.created_at - a.created_at);
275→          return next.slice(0, MAX_NOTES);
276→        });
277→        ensureProfile(ev.pubkey);
278→      };
279→
280→      const handleNotification = (packet: { event: { id: string; kind: number; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
281→        if (packet.event.pubkey === hex) return; // skip own actions
282→        addNotification(packet.event);
283→      };
284→
285→      // Mentions: kind:1 where owner is p-tagged
286→      const mentionPastReq = createRxBackwardReq();
287→      rxNostr.use(mentionPastReq).pipe(uniq()).subscribe(handleNotification);
288→      mentionPastReq.emit([{ kinds: [1], "#p": [hex], limit: 30 }]);
289→      mentionPastReq.over();
290→
291→      const mentionLiveReq = createRxForwardReq();
292→      rxNostr.use(mentionLiveReq).pipe(uniq()).subscribe(handleNotification);
293→      mentionLiveReq.emit([{ kinds: [1], "#p": [hex] }]);
294→
295→      // Reactions/reposts directed at owner (kind:7, kind:6)
296→      const notifReactionPastReq = createRxBackwardReq();
297→      rxNostr.use(notifReactionPastReq).pipe(uniq()).subscribe(handleNotification);
298→      notifReactionPastReq.emit([{ kinds: [7, 6], "#p": [hex], limit: 50 }]);
299→      notifReactionPastReq.over();
300→
301→      const notifReactionLiveReq = createRxForwardReq();
302→      rxNostr.use(notifReactionLiveReq).pipe(uniq()).subscribe(handleNotification);
303→      notifReactionLiveReq.emit([{ kinds: [7, 6], "#p": [hex] }]);
304→
305→      // Reactions deck: all kind:7 events on followed TL
306→      const addReaction = (ev: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] }) => {
307→        const targetNoteId = ev.tags.find((t) => t[0] === "e")?.[1];
308→        if (!targetNoteId) return;
309→        setReactions((prev) => {
310→          if (prev.some((r) => r.id === ev.id)) return prev;
311→          const next = [{ id: ev.id, pubkey: ev.pubkey, content: ev.content, created_at: ev.created_at, targetNoteId }, ...prev];
312→          next.sort((a, b) => b.created_at - a.created_at);
313→          return next.slice(0, MAX_NOTES);
314→        });
315→        ensureProfile(ev.pubkey);
316→      };
317→
318→      const handleReactionEvent = (packet: { event: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] } }) => {
319→        addReaction(packet.event);
320→      };
321→
322→      const reactionDeckPastReq = createRxBackwardReq();
323→      rxNostr.use(reactionDeckPastReq).pipe(uniq()).subscribe(handleReactionEvent);
324→      reactionDeckPastReq.emit([{ kinds: [7], "#p": authors, limit: 50 }]);
325→      reactionDeckPastReq.over();
326→
327→      const reactionDeckLiveReq = createRxForwardReq();
328→      rxNostr.use(reactionDeckLiveReq).pipe(uniq()).subscribe(handleReactionEvent);
329→      reactionDeckLiveReq.emit([{ kinds: [7], "#p": authors }]);
330→    })();
331→
332→    return () => {
333→      disposed = true;
334→      disposeFnRef.current?.();
335→      disposeFnRef.current = null;
336→      setIsConnected(false);
337→    };
338→  }, []);
339→
340→  // Derived data for deck columns
341→  const myNotes = useMemo(
342→    () => (ownerHex ? notes.filter((n) => n.pubkey === ownerHex) : []),
343→    [notes, ownerHex],
344→  );
345→
346→  const timelineNotes = useMemo(
347→    () => (ownerHex ? notes.filter((n) => n.pubkey !== ownerHex) : notes),
348→    [notes, ownerHex],
349→  );
350→
351→  const taggedNotes = useMemo(
352→    () => notes.filter((n) => n.tags.some((t) => t[0] === "t")),
353→    [notes],
354→  );
355→
356→  const isOwner = !!(signerPubkey && ownerHex && signerPubkey === ownerHex);
357→
358→  const publish = useCallback(async (content: string) => {
359→    if (!window.nostr || !rxNostrRef.current || !isOwner) {
360→      throw new Error("Cannot publish: not logged in as owner");
361→    }
362→    setIsPublishing(true);
363→    try {
364→      const unsignedEvent = {
365→        kind: 1,
366→        content,
367→        tags: [] as string[][],
368→        created_at: Math.floor(Date.now() / 1000),
369→      };
370→      const signedEvent = await window.nostr.signEvent(unsignedEvent);
