 1→import { count, eq, desc, and, type SQL } from "drizzle-orm";
 2→import type { Route } from "./+types/radar-items";
 3→import { radarItems as radarItemsTable, sources } from "../../../db/schema";
 4→
 5→const ITEMS_PER_PAGE = 20;
 6→
 7→export async function loader({ request, context }: Route.LoaderArgs) {
 8→  const url = new URL(request.url);
 9→  const page = parseInt(url.searchParams.get("page") || "1");
10→  const offset = (page - 1) * ITEMS_PER_PAGE;
11→  const kindParam = url.searchParams.get("kind");
12→  const categoryParam = url.searchParams.get("category");
13→  const sourceParam = url.searchParams.get("source");
14→
15→  const conditions: SQL[] = [];
16→  if (kindParam && kindParam !== "all") {
17→    conditions.push(eq(sources.kind, kindParam));
18→  }
19→  if (categoryParam && categoryParam !== "all") {
20→    conditions.push(eq(sources.categorySlug, categoryParam));
21→  }
22→  if (sourceParam && sourceParam !== "all") {
23→    conditions.push(eq(radarItemsTable.source, sourceParam));
24→  }
25→
26→  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;
27→
28→  const [totalCountResult, radarItems] = await Promise.all([
29→    context.db
30→      .select({ count: count() })
31→      .from(radarItemsTable)
32→      .innerJoin(sources, eq(radarItemsTable.source, sources.id))
33→      .where(whereClause),
34→    context.db
35→      .select({
36→        id: radarItemsTable.id,
37→        title: radarItemsTable.title,
38→        source: radarItemsTable.source,
39→        sourceName: radarItemsTable.sourceName,
40→        summary: radarItemsTable.summary,
41→        image: radarItemsTable.image,
42→        url: radarItemsTable.url,
43→        type: radarItemsTable.type,
44→        metadata: radarItemsTable.metadata,
45→        timestamp: radarItemsTable.timestamp,
46→        createdAt: radarItemsTable.createdAt,
47→        updatedAt: radarItemsTable.updatedAt,
48→        category: sources.category,
49→        categorySlug: sources.categorySlug,
50→        kind: sources.kind,
51→      })
52→      .from(radarItemsTable)
53→      .innerJoin(sources, eq(radarItemsTable.source, sources.id))
54→      .where(whereClause)
55→      .orderBy(desc(radarItemsTable.timestamp))
56→      .limit(ITEMS_PER_PAGE)
57→      .offset(offset),
58→  ]);
59→
60→  const totalCount = totalCountResult[0]?.count ?? 0;
61→  const hasMore = offset + radarItems.length < totalCount;
62→
63→  return {
64→    radarItems,
65→    hasMore,
66→    currentPage: page,
67→    totalCount,
68→  };
69→}
