129→function DeckColumn({
130→  categorySlug,
131→  initialItems,
132→  initialHasMore,
133→  selectedKind,
134→  selectedPeriod,
135→}: {
136→  categorySlug: string;
137→  initialItems: RadarItemWithCategory[];
138→  initialHasMore: boolean;
139→  selectedKind: Kind;
140→  selectedPeriod: Period;
141→}) {
142→  const cat = getCategoryBySlug(categorySlug);
143→  const fetcher = useFetcher<FetchRadarItemsResponse>();
144→  const [items, setItems] = useState(initialItems);
145→  const [hasMore, setHasMore] = useState(initialHasMore);
146→  const [page, setPage] = useState(1);
147→  const isLoadingRef = useRef(false);
148→
149→  useEffect(() => {
150→    setItems(initialItems);
151→    setHasMore(initialHasMore);
152→    setPage(1);
153→  }, [initialItems, initialHasMore]);
154→
155→  useEffect(() => {
156→    const data = fetcher.data;
157→    if (data?.radarItems) {
158→      setItems((prev) => [...prev, ...data.radarItems]);
159→      setHasMore(data.hasMore);
160→      isLoadingRef.current = false;
161→    }
162→  }, [fetcher.data]);
163→
164→  const loadMore = useCallback(() => {
165→    if (!hasMore || fetcher.state !== "idle" || isLoadingRef.current) return;
166→    isLoadingRef.current = true;
167→    const nextPage = page + 1;
168→    setPage(nextPage);
169→    const params = new URLSearchParams({
170→      page: String(nextPage),
171→      category: categorySlug,
172→    });
173→    if (selectedKind !== "all") params.set("kind", selectedKind);
174→    fetcher.load(`/api/radar-items?${params.toString()}`);
175→  }, [hasMore, page, fetcher, categorySlug, selectedKind]);
176→
177→  const { ref: sentinelRef, inView } = useInView({
178→    threshold: 0,
179→    rootMargin: "200px",
180→  });
181→
182→  useEffect(() => {
183→    if (inView && hasMore && fetcher.state === "idle") {
184→      loadMore();
185→    }
186→  }, [inView, hasMore, fetcher.state, loadMore]);
187→
188→  const filteredItems = items.filter((f) => {
189→    if (selectedPeriod === "All") return true;
190→    const now = new Date();
191→    const itemDate = new Date(f.timestamp);
192→    if (selectedPeriod === "Today") {
193→      return itemDate.toDateString() === now.toDateString();
194→    }
195→    if (selectedPeriod === "Month") {
196→      const oneMonthAgo = new Date();
197→      oneMonthAgo.setMonth(oneMonthAgo.getMonth() - 1);
198→      return itemDate >= oneMonthAgo;
199→    }
200→    return true;
201→  });
202→
203→  return (
204→    <div className="flex flex-col h-full w-96 flex-shrink-0 bg-white overflow-hidden">
205→      <div className="px-3 py-2 border-b border-gray-200 bg-white text-gray-900">
206→        <span className="text-sm font-semibold">{cat.name}</span>
207→      </div>
208→
209→      <div className="flex-1 overflow-y-auto">
210→        {filteredItems.length === 0 ? (
211→          <div className="p-4 text-center text-xs text-gray-400">
212→            アイテムなし
213→          </div>
214→        ) : (
215→          filteredItems.map((item) => <FeedCard key={item.id} item={item} />)
216→        )}
217→
218→        {hasMore && (
219→          <div ref={sentinelRef} className="py-3 flex justify-center">
220→            {fetcher.state !== "idle" && (
221→              <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-gray-400" />
222→            )}
223→          </div>
224→        )}
225→      </div>
226→    </div>
227→  );
228→}
