106→// 日付を相対時間でフォーマットするユーティリティ関数
107→export function formatRelativeTime(date: Date): string {
108→  const now = new Date();
109→  const diffMs = now.getTime() - date.getTime();
110→  const diffSeconds = Math.floor(diffMs / 1000);
111→  const diffMinutes = Math.floor(diffSeconds / 60);
112→  const diffHours = Math.floor(diffMinutes / 60);
113→  const diffDays = Math.floor(diffHours / 24);
114→
115→  if (diffDays > 7) {
116→    return date.toLocaleDateString('ja-JP', { month: 'short', day: 'numeric' });
117→  } else if (diffDays > 0) {
118→    return `${diffDays}日前`;
119→  } else if (diffHours > 0) {
120→    return `${diffHours}時間前`;
121→  } else if (diffMinutes > 0) {
122→    return `${diffMinutes}分前`;
123→  } else {
124→    return 'たった今';
125→  }
126→}
