171→function normalizePeriod(value: string): Period {
172→  return value === "Today" || value === "Month" || value === "All" ? value : "All";
173→}
174→
175→function normalizeKind(value: string): Kind {
176→  return ["all", "articles", "releases", "video", "podcast", "twitter"].includes(value)
177→    ? (value as Kind)
178→    : "all";
179→}
