import { useState, useEffect, useCallback, useRef } from "react";
import { useFetcher } from "react-router";
import { useInView } from "react-intersection-observer";
import { useQueryStates, parseAsString } from "nuqs";
import { count, eq, desc, and, type SQL } from "drizzle-orm";
import type { Route } from "./+types/home";
import { AppLayout } from "~/components/layout";
import { CardGrid, TweetTimeline, DeckView } from "~/components/feed";
import { Favicon } from "~/components/ui";
import { categoryList, getDomainFromUrl, type FetchRadarItemsResponse, type RadarItemWithCategory, type DeckData, type Period, type Kind } from "~/data/types";
import { radarItems, sources } from "../../db/schema";

export function meta({}: Route.MetaArgs) {
  return [
    { title: "Radar" },
    { name: "description", content: "Tech radar aggregator" },
  ];
}

const ITEMS_PER_PAGE = 20;
const DECK_ITEMS_PER_COLUMN = 10;

const itemSelectFields = {
  id: radarItems.id,
  title: radarItems.title,
  source: radarItems.source,
  sourceName: radarItems.sourceName,
  summary: radarItems.summary,
  image: radarItems.image,
  url: radarItems.url,
  type: radarItems.type,
  metadata: radarItems.metadata,
  timestamp: radarItems.timestamp,
  createdAt: radarItems.createdAt,
  updatedAt: radarItems.updatedAt,
  category: sources.category,
  categorySlug: sources.categorySlug,
  kind: sources.kind,
};

export async function loader({ request, context }: Route.LoaderArgs) {
  const url = new URL(request.url);
  const categoryParam = url.searchParams.get("category");
  const kindParam = url.searchParams.get("kind");
  const sourceParam = url.searchParams.get("source");

  const isDeckMode =
    (!categoryParam || categoryParam === "all") &&
    (!sourceParam || sourceParam === "all") &&
    (!kindParam || kindParam === "all");

  const [sourcesData, sourceCountRows] = await Promise.all([
    context.db.query.sources.findMany({
      orderBy: (sources, { asc }) => [asc(sources.name)],
    }),
    context.db
      .select({ source: radarItems.source, count: count() })
      .from(radarItems)
      .groupBy(radarItems.source),
  ]);

  const sourceArticleCounts = Object.fromEntries(
    sourceCountRows.map((row) => [row.source, row.count]),
  );

  if (isDeckMode) {
    const activeCats = categoryList.filter((c) => c.slug !== "all");

    const categoryResults = await Promise.all(
      activeCats.map((cat) => {
        const conditions = [
          eq(sources.categorySlug, cat.slug),
        ];
        return context.db
          .select(itemSelectFields)
          .from(radarItems)
          .innerJoin(sources, eq(radarItems.source, sources.id))
          .where(and(...conditions))
          .orderBy(desc(radarItems.timestamp))
          .limit(DECK_ITEMS_PER_COLUMN + 1);
      }),
    );

    const deckData: DeckData = {};
    activeCats.forEach((cat, i) => {
      const rows = categoryResults[i];
      const hasMore = rows.length > DECK_ITEMS_PER_COLUMN;
      deckData[cat.slug] = {
        items: hasMore ? rows.slice(0, DECK_ITEMS_PER_COLUMN) : rows,
        hasMore,
      };
    });

    return {
      deckData,
      sources: sourcesData,
      sourceArticleCounts,
      radarItems: [] as RadarItemWithCategory[],
      hasMore: false,
      currentPage: 1,
    };
  }

  // Non-deck mode: existing behavior
  const conditions: SQL[] = [];
  if (kindParam && kindParam !== "all") {
    conditions.push(eq(sources.kind, kindParam));
  }
  if (categoryParam && categoryParam !== "all") {
    conditions.push(eq(sources.categorySlug, categoryParam));
  }
  if (sourceParam && sourceParam !== "all") {
    conditions.push(eq(radarItems.source, sourceParam));
  }
  const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

  const [totalCountResult, items] = await Promise.all([
    context.db
      .select({ count: count() })
      .from(radarItems)
      .innerJoin(sources, eq(radarItems.source, sources.id))
      .where(whereClause),
    context.db
      .select(itemSelectFields)
      .from(radarItems)
      .innerJoin(sources, eq(radarItems.source, sources.id))
      .where(whereClause)
      .orderBy(desc(radarItems.timestamp))
      .limit(ITEMS_PER_PAGE),
  ]);

  const totalCount = totalCountResult[0]?.count ?? 0;
  const hasMore = items.length < totalCount;

  return {
    deckData: null as DeckData | null,
    radarItems: items,
    sources: sourcesData,
    sourceArticleCounts,
    hasMore,
    currentPage: 1,
  };
}

function CategoryFilter({
  selectedCategorySlug,
  onSelect,
}: {
  selectedCategorySlug: string;
  onSelect: (slug: string) => void;
}) {
  return (
    <div className="flex gap-1.5 overflow-x-auto pb-1 mt-3">
      {categoryList.map((cat) => (
        <button
          key={cat.slug}
          onClick={() => onSelect(cat.slug)}
          className={`px-2.5 py-1 text-xs rounded-full whitespace-nowrap transition-colors ${
            selectedCategorySlug === cat.slug
              ? "bg-gray-800 text-white"
              : "bg-gray-100 text-gray-500 hover:bg-gray-200 hover:text-gray-600"
          }`}
        >
          {cat.name}
        </button>
      ))}
    </div>
  );
}

function normalizePeriod(value: string): Period {
  return value === "Today" || value === "Month" || value === "All" ? value : "All";
}

function normalizeKind(value: string): Kind {
  return ["all", "articles", "releases", "video", "podcast", "twitter"].includes(value)
    ? (value as Kind)
    : "all";
}

export default function Home({ loaderData }: Route.ComponentProps) {
  const fetcher = useFetcher<FetchRadarItemsResponse>();

  const [query, setQuery] = useQueryStates(
    {
      category: parseAsString.withDefault("all"),
      source: parseAsString.withDefault("all"),
      period: parseAsString.withDefault("All"),
      kind: parseAsString.withDefault("all"),
    },
    { history: "replace" },
  );

  const categorySlug = query.category;
  const selectedSource = query.source;
  const selectedPeriod = normalizePeriod(query.period);
  const selectedKind = normalizeKind(query.kind);

  const isDeckMode = categorySlug === "all" && selectedSource === "all" && selectedKind === "all";

  const setSelectedKind = useCallback((kind: Kind) => {
    void setQuery({ kind });
  }, [setQuery]);

  const setSelectedPeriod = useCallback((period: Period) => {
    void setQuery({ period });
  }, [setQuery]);

  const handleSourceChange = useCallback((source: string) => {
    if (source !== "all") {
      void setQuery({ source, kind: "all", category: "all" });
      return;
    }
    void setQuery({ source });
  }, [setQuery]);

  const handleCategoryChange = useCallback((category: string) => {
    void setQuery({ category, source: "all" });
  }, [setQuery]);

  // --- Non-deck mode state ---
  const [items, setItems] = useState<FetchRadarItemsResponse["radarItems"]>(
    loaderData.radarItems as FetchRadarItemsResponse["radarItems"],
  );
  const [page, setPage] = useState(loaderData.currentPage);
  const [hasMore, setHasMore] = useState(loaderData.hasMore);
  const [isLoading, setIsLoading] = useState(false);
  const isResetRef = useRef(false);

  const isFirstRender = useRef(true);
  useEffect(() => {
    if (isFirstRender.current) {
      isFirstRender.current = false;
      return;
    }

    if (isDeckMode) return;

    setItems([]);
    setPage(1);
    setHasMore(true);
    setIsLoading(true);
    isResetRef.current = true;

    const params = new URLSearchParams({ page: "1" });
    if (selectedKind !== "all") params.set("kind", selectedKind);
    if (categorySlug !== "all") params.set("category", categorySlug);
    if (selectedSource !== "all") params.set("source", selectedSource);

    fetcher.load(`/api/radar-items?${params.toString()}`);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedKind, selectedSource, categorySlug]);

  // 無限スクロール: 次ページ読み込み
  const loadMore = useCallback(() => {
    if (hasMore && fetcher.state === "idle" && !isLoading) {
      const nextPage = page + 1;
      setPage(nextPage);
      setIsLoading(true);
      isResetRef.current = false;
      const params = new URLSearchParams({ page: String(nextPage) });
      if (selectedKind !== "all") params.set("kind", selectedKind);
      if (categorySlug !== "all") params.set("category", categorySlug);
      if (selectedSource !== "all") params.set("source", selectedSource);
      fetcher.load(`/api/radar-items?${params.toString()}`);
    }
  }, [hasMore, page, fetcher, isLoading, selectedKind, categorySlug, selectedSource]);

  // fetcher レスポンス処理
  useEffect(() => {
    const data = fetcher.data;
    if (data?.radarItems) {
      if (isResetRef.current) {
        setItems(data.radarItems);
        isResetRef.current = false;
      } else {
        setItems((prev) => [...prev, ...data.radarItems]);
      }
      setHasMore(data.hasMore);
      setIsLoading(false);
    }
  }, [fetcher.data]);

  const { ref: observerRef, inView } = useInView({
    threshold: 0,
    rootMargin: "100px",
  });

  useEffect(() => {
    if (inView && hasMore && fetcher.state === "idle" && !isLoading) {
      loadMore();
    }
  }, [inView, hasMore, fetcher.state, loadMore, isLoading]);

  // period のみクライアントサイドフィルタ
  const filteredItems = items.filter((f) => {
    if (selectedPeriod === "All") return true;
    const now = new Date();
    const itemDate = new Date(f.timestamp);
    if (selectedPeriod === "Today") {
      return itemDate.toDateString() === now.toDateString();
    }
    if (selectedPeriod === "Month") {
      const oneMonthAgo = new Date();
      oneMonthAgo.setMonth(oneMonthAgo.getMonth() - 1);
      return itemDate >= oneMonthAgo;
    }
    return true;
  });

  const selectedSourceData = selectedSource !== "all"
    ? loaderData.sources.find((s) => s.id === selectedSource)
    : undefined;
  const selectedSourceCount = selectedSourceData
    ? loaderData.sourceArticleCounts[selectedSourceData.id] ?? 0
    : 0;

  return (
    <AppLayout
      title="Radar"
      selectedSource={selectedSource}
      setSelectedSource={handleSourceChange}
      selectedPeriod={selectedPeriod}
      setSelectedPeriod={setSelectedPeriod}
      selectedKind={selectedKind}
      setSelectedKind={setSelectedKind}
      showSourceFilter={true}
      sources={loaderData.sources}
      isDeckMode={isDeckMode}
      headerContent={
        isDeckMode ? undefined : (
          selectedSourceData ? (
            <div className="flex items-center gap-2.5">
              <Favicon domain={getDomainFromUrl(selectedSourceData.url)} size={20} />
              <span className="text-sm font-medium text-gray-900">{selectedSourceData.name}</span>
              <span className="text-xs text-gray-400">{selectedSourceCount} articles</span>
            </div>
          ) : (
            <CategoryFilter selectedCategorySlug={categorySlug} onSelect={handleCategoryChange} />
          )
        )
      }
    >
      {isDeckMode && loaderData.deckData ? (
        <DeckView
          deckData={loaderData.deckData}
          selectedKind={selectedKind}
          selectedPeriod={selectedPeriod}
        />
      ) : (
        <>
          {selectedKind === "twitter" ? (
            <div className="-m-4">
              <TweetTimeline items={filteredItems} />
            </div>
          ) : (
            <CardGrid items={filteredItems} />
          )}
          {filteredItems.length === 0 && (
            <div className="text-center py-12 text-gray-500">
              該当する記事がありません
            </div>
          )}

          {hasMore && filteredItems.length > 0 && (
            <div ref={observerRef} className="p-2.5 text-center">
              {isLoading && (
                <div className="flex justify-center items-center">
                  <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-gray-900"></div>
                </div>
              )}
            </div>
          )}
        </>
      )}
    </AppLayout>
  );
}

