export interface NostrNote {
  id: string;
  pubkey: string;
  content: string;
  created_at: number;
  tags: string[][];
}

export interface NostrProfile {
  name?: string;
  display_name?: string;
  picture?: string;
  about?: string;
}

export interface NoteStats {
  reactions: number;
  reposts: number;
}

export interface NostrNotification {
  id: string;
  kind: number;
  pubkey: string;
  content: string;
  created_at: number;
  tags: string[][];
  targetNoteId?: string;
}

export interface NostrReaction {
  id: string;
  pubkey: string;
  content: string;
  created_at: number;
  targetNoteId: string;
}

declare global {
  interface Window {
    nostr?: {
      getPublicKey(): Promise<string>;
      signEvent(event: unknown): Promise<unknown>;
    };
  }
}

const MAX_NOTES = 200;

function addNote(
  prev: NostrNote[],
  ev: { id: string; pubkey: string; content: string; created_at: number; tags: string[][] },
) {
  if (prev.some((n) => n.id === ev.id)) return prev;
  const next = [
    { id: ev.id, pubkey: ev.pubkey, content: ev.content, created_at: ev.created_at, tags: ev.tags },
    ...prev,
  ];
  next.sort((a, b) => b.created_at - a.created_at);
  return next.slice(0, MAX_NOTES);
}

