import { useState, useEffect, useCallback, useRef, type ReactNode } from "react";
import { useFetcher } from "react-router";
import { useInView } from "react-intersection-observer";
import type {
  RadarItemWithCategory,
  TweetMetadata,
  DeckData,
  FetchRadarItemsResponse,
